import React from 'react'
import useBook from '../hooks/useBook';
import { Outlet, useNavigate } from 'react-router-dom';
import { Button, TextField, Grid, Paper } from '@mui/material';
import { Search, FilterList } from '@mui/icons-material';
import appTheme from '../theme';
import { borderRadius } from '@mui/system';

const SearchBar = () => {

    const { search, dataSearch, getBookList, loading } = useBook()

    const { query } = search

    const navigate = useNavigate();

    const textFieldStyles = {
        backgroundColor: 'rgba(119,154,74,0.25)',
        padding: '0'
    }

    const handleSubmit = e => {
        e.preventDefault()
        getBookList(query, loading)
        navigate("list", { replace: true });
    }

  return (
      <>
      
        <form onSubmit={handleSubmit}>
       
            <Grid container justifyContent="center" alignItems="center" spacing={0} p={2}>
            <Grid item xs={8}>
                <TextField
                fullWidth
                label='Buscar por título, autor...'
                type="text"
                name="query"
                onChange={dataSearch}
                value={query}
                variant="filled"
                size="small"
                sx={textFieldStyles}
                InputProps={{
                    disableUnderline: true,
                    sx: {
                        borderBottom: 'none',
                        
                }
                  }}
                InputLabelProps={{
                    sx: { color: appTheme.palette.primary.dark, fontWeight: '500', fontSize: '14px' }
                }}
                />
            </Grid>
            <Grid item xs='2'>
                <Button type="button" variant="contained" color="primary" style={{borderRadius: '0'}}  onClick={() => {}}>
                <FilterList sx={{ height: '100%', width: '100%' }}/>
                </Button>
            </Grid>
            <Grid item xs='2'>
                <Button type="submit" variant="contained" style={{borderRadius: '0'}} color="primary">
                <Search sx={{ height: '100%', width: '100%' }}/>
                </Button>
            </Grid>
            </Grid>
       
        </form>
        <Outlet></Outlet>
      </>
        
  )
}

export default SearchBar
